import pg from "pg";
import crypto from "crypto";
const Pool = pg.Pool;
const pool = new Pool({ connectionString: process.env.PROD_DATABASE_URL || process.env.DATABASE_URL });
function hash(s: string): string { return crypto.createHash("md5").update(s.toLowerCase().trim()).digest("hex"); }

interface Q {
  tier: string; exam: string; stem: string; options: string[];
  correct: number; rationale: string; diff: number; bs: string;
  topic: string; subtopic: string; tags: string[]; clinicalPearl: string;
}

function q(bs: string, d: number, s: string, o: string[], c: number, r: string, topic: string, subtopic: string, tags: string[], pearl: string): Q {
  return { tier: "rn", exam: "NCLEX-RN", stem: s, options: o, correct: c, rationale: r, diff: d, bs, topic, subtopic, tags, clinicalPearl: pearl };
}

const QS: Q[] = [
  // ============================================================
  // CARDIAC ADDITIONAL (25 questions)
  // ============================================================
  q("Cardiovascular", 3, "A client with stable angina is prescribed sublingual nitroglycerin. The nurse teaches the client that if chest pain is not relieved after the first tablet, the client should:", ["Take 3 more tablets immediately", "Call 911 immediately and take a second tablet in 5 minutes if prescribed", "Wait 30 minutes before taking another tablet", "Drive to the nearest emergency room"], 1, "Current AHA guidelines recommend calling 911 after the first dose of NTG if pain is not relieved in 5 minutes. A second dose can be taken 5 minutes after the first while waiting for EMS. Maximum 3 tablets, 5 minutes apart. Do not delay calling emergency services. Option A is unsafe. Option C delays treatment. Option D is dangerous while having chest pain.", "Angina", "Nitroglycerin Protocol", ["cardiac", "angina", "nitroglycerin", "emergency"], "Updated NTG protocol: take 1 tab, call 911 if no relief in 5 min, may take 2 more tabs q5min while waiting. Old protocol was take 3 then call — this has changed."),

  q("Cardiovascular", 4, "A nurse is caring for a client with acute mitral valve regurgitation. Which hemodynamic finding supports this diagnosis?", ["Decreased pulmonary artery wedge pressure", "Tall V waves on the pulmonary artery wedge pressure tracing", "Elevated central venous pressure only", "Normal cardiac output"], 1, "Acute mitral regurgitation causes blood to regurgitate into the left atrium during systole, producing tall (giant) V waves on the PAWP waveform. This is a classic hemodynamic finding. Other findings include decreased cardiac output, elevated PAWP, and pulmonary edema. Option A would indicate hypovolemia. Option C is seen in right-sided failure. Option D is unlikely in acute MR.", "Valvular Heart Disease", "Hemodynamic Monitoring", ["cardiac", "mitral-regurgitation", "hemodynamics", "critical-care"], "Giant V waves on PAWP tracing = mitral regurgitation. A waves = atrial contraction. Giant A waves = tricuspid stenosis or AV dissociation."),

  q("Cardiovascular", 2, "A nurse is caring for a client who has just received a coronary stent. Which discharge instruction is most important?", ["Resume all normal activities immediately", "Take dual antiplatelet therapy as prescribed and do not stop without consulting your cardiologist", "Avoid all physical activity for 6 months", "Follow up with the cardiologist in 1 year"], 1, "Premature discontinuation of dual antiplatelet therapy (DAPT) after coronary stenting is the #1 cause of stent thrombosis, which carries 20-40% mortality. Clients must understand they cannot stop aspirin or clopidogrel (or ticagrelor/prasugrel) without cardiology approval, even for elective procedures. Option A may be premature. Option C is overly restrictive. Option D delays necessary follow-up.", "Coronary Stenting", "Discharge Teaching", ["cardiac", "stent", "antiplatelet", "patient-education"], "Post-stent discharge: #1 teaching point = never stop DAPT without cardiology approval. Schedule dental work BEFORE stenting if possible. Inform all providers about stent and medications."),

  q("Cardiovascular", 3, "A client with chronic stable heart failure has a BNP level of 850 pg/mL. The nurse interprets this as:", ["Normal finding", "Elevated, indicating worsening heart failure", "Low, suggesting the heart failure is well controlled", "Diagnostic of myocardial infarction"], 1, "BNP (B-type natriuretic peptide) is released by ventricular myocytes in response to volume overload and wall stretch. Normal BNP is <100 pg/mL. Levels >400 pg/mL strongly suggest heart failure. A level of 850 pg/mL indicates significant ventricular dysfunction and fluid overload requiring intensification of therapy. Option A is incorrect. Option C is wrong. Option D — BNP indicates HF, not MI (troponin is for MI).", "Heart Failure", "BNP Monitoring", ["cardiac", "heart-failure", "BNP", "lab-values"], "BNP interpretation: <100 = HF unlikely, 100-400 = gray zone, >400 = HF likely. NT-proBNP: <300 = HF unlikely, >900 = HF likely. Trend values are more useful than single measurements."),

  q("Cardiovascular", 3, "A nurse is assessing a client with a ventricular assist device (VAD). The nurse cannot obtain a blood pressure by auscultation. This is because:", ["The VAD is malfunctioning", "Continuous-flow VADs produce non-pulsatile flow, making traditional BP measurement unreliable; use Doppler to obtain MAP", "The client has no cardiac output", "The blood pressure cuff is too small"], 1, "Modern continuous-flow VADs (HeartMate 3, HVAD) provide non-pulsatile blood flow, meaning there is no systolic/diastolic difference. A Doppler probe is used to obtain mean arterial pressure (MAP), which should be maintained at 70-90 mmHg. The client may not have a palpable pulse. Option A is premature. Option C — the VAD is providing output. Option D is unrelated to the VAD.", "Ventricular Assist Devices", "BP Assessment", ["cardiac", "VAD", "assessment", "critical-care"], "VAD assessment: no pulse may be normal (continuous flow). Use Doppler for MAP (target 70-90). Monitor: pump speed, flow, power, pulsatility index. Anticoagulation with warfarin is essential."),

  q("Cardiovascular", 2, "A client asks how to check their radial pulse at home. The nurse should teach:", ["Use the thumb to palpate the wrist", "Use the index and middle fingers on the inner wrist below the thumb, count for a full 60 seconds", "Press firmly with all fingers", "Check the pulse for 10 seconds and multiply by 6"], 1, "Proper pulse assessment: use the pads of the index and middle fingers (NOT the thumb — it has its own pulse that can be confused with the client's). Palpate the radial artery on the inner wrist, lateral to the flexor tendon. Count for a full 60 seconds to detect irregularities. For atrial fibrillation, a full 60-second count is essential due to irregular rhythm. Option A uses the thumb. Option C may occlude the artery. Option D may miss irregularities.", "Vital Signs", "Pulse Assessment", ["cardiac", "vital-signs", "assessment", "patient-education"], "Pulse assessment: never use thumb (has its own pulse). Full 60 seconds for irregular rhythms. Note rate, rhythm, and quality. Apical pulse is gold standard for irregularities."),

  q("Cardiovascular", 3, "A client is experiencing symptomatic bradycardia with a heart rate of 38 bpm. According to ACLS guidelines, the first-line medication is:", ["Epinephrine", "Atropine 1 mg IV", "Amiodarone", "Lidocaine"], 1, "Per ACLS algorithm for symptomatic bradycardia: first-line treatment is atropine 0.5-1 mg IV every 3-5 minutes (max 3 mg). If atropine is ineffective, consider transcutaneous pacing, dopamine infusion (5-20 mcg/kg/min), or epinephrine infusion (2-10 mcg/min). Option A is second-line. Options C and D are for tachycardia, not bradycardia.", "Dysrhythmias", "Symptomatic Bradycardia", ["cardiac", "ACLS", "bradycardia", "pharmacology"], "Symptomatic bradycardia ACLS: 1st = atropine 0.5-1 mg IV q3-5min (max 3 mg). 2nd = transcutaneous pacing, dopamine drip, or epinephrine drip. Atropine is NOT effective for Mobitz Type II or 3rd degree block."),

  q("Cardiovascular", 3, "A nurse is caring for a client with an abdominal aortic aneurysm (AAA) who suddenly develops severe tearing abdominal pain radiating to the back with rapidly falling blood pressure. The nurse suspects:", ["Appendicitis", "AAA rupture requiring emergent surgical intervention", "Gastric ulcer perforation", "Renal colic"], 1, "Sudden severe tearing abdominal/back pain with hemodynamic instability in a client with known AAA indicates rupture — a surgical emergency with high mortality. Immediate actions: establish large-bore IV access, type and crossmatch, prepare for emergent surgery, and do NOT delay for imaging if the client is unstable. Option A presents differently. Option C can cause peritonitis but not this presentation. Option D does not cause hypotension.", "Aortic Aneurysm", "Rupture Recognition", ["cardiac", "AAA", "emergency", "vascular"], "AAA rupture: sudden tearing pain, hypotension, pulsatile abdominal mass. Do NOT palpate a known AAA aggressively. Emergent surgery. Mortality >80% if rupture occurs outside the hospital."),

  q("Cardiovascular", 3, "A client recovering from cardiac surgery develops atrial fibrillation on postoperative day 2. The nurse understands this occurs in approximately:", ["1-2% of post-cardiac surgery patients", "25-40% of post-cardiac surgery patients, making it the most common postoperative dysrhythmia", "Less than 1% of patients", "Only in patients with pre-existing AFib"], 1, "Post-operative atrial fibrillation occurs in 25-40% of cardiac surgery patients, peaking on postoperative days 2-3. Risk factors include advanced age, valve surgery, and prolonged cross-clamp time. Treatment includes rate control (beta-blockers, amiodarone), anticoagulation if sustained, and electrolyte correction. Option A and C significantly underestimate. Option D is incorrect.", "Post-Cardiac Surgery", "Atrial Fibrillation", ["cardiac", "post-surgical", "AFib", "dysrhythmia"], "Post-cardiac surgery AFib: very common (25-40%), peaks POD 2-3. Risk factors: age, valve surgery. Treatment: amiodarone, beta-blockers, correct electrolytes (especially Mg2+ and K+)."),

  q("Cardiovascular", 4, "A nurse is caring for a client with an intra-aortic balloon pump (IABP). The balloon should inflate during:", ["Systole", "Diastole, as indicated by the dicrotic notch on the arterial waveform", "Both systole and diastole equally", "Only during deep inspiration"], 1, "IABP timing: the balloon inflates during diastole (triggered by the dicrotic notch — aortic valve closure) to augment coronary perfusion and deflates just before systole to reduce afterload (afterload reduction). This counterpulsation improves cardiac output and reduces myocardial oxygen demand. Option A would increase afterload. Option C is incorrect timing. Option D is unrelated.", "Mechanical Circulatory Support", "IABP Timing", ["cardiac", "IABP", "critical-care", "hemodynamics"], "IABP: inflate in diastole (augments coronary perfusion), deflate before systole (reduces afterload). Monitor: timing on arterial waveform, peripheral pulses, anticoagulation, and limb perfusion."),

  // ============================================================
  // RESPIRATORY ADDITIONAL (20 questions)
  // ============================================================
  q("Respiratory", 3, "A client with asthma has a peak expiratory flow rate (PEFR) that is 50% of their personal best. According to the asthma action plan, the zone color is:", ["Green zone — well controlled", "Yellow zone — caution, increase medication", "Red zone — medical emergency", "No specific zone applies"], 1, "Asthma traffic light system: Green zone (80-100% of personal best) = well controlled. Yellow zone (50-79%) = caution, symptoms increasing, use rescue inhaler and possibly increase controller medications. Red zone (<50%) = medical emergency, use rescue inhaler and seek immediate medical care. At 50%, the client is in the yellow zone.", "Asthma", "Peak Flow Monitoring", ["respiratory", "asthma", "peak-flow", "self-management"], "Asthma zones: Green (80-100%) = go. Yellow (50-79%) = caution. Red (<50%) = emergency. Teach clients to know their personal best PEFR and use action plan accordingly."),

  q("Respiratory", 3, "A nurse is caring for a client with a right-sided chest tube. The nurse notices the water-seal chamber is not fluctuating (tidaling). The nurse should first:", ["Assume the lung has re-expanded and prepare for chest tube removal", "Check for kinks in the tubing, ensure tubing is not clamped, and have the client cough or change position", "Increase suction to restore fluctuation", "Immediately notify the provider"], 1, "Absence of tidaling can indicate: lung re-expansion (desired), tubing obstruction/kinking, dependent loops, or system disconnection. The nurse should first troubleshoot — check for kinks, straighten tubing, ensure no clamps are on, and have the client reposition or cough. If tidaling resumes, the issue was mechanical. If not, the lung may have re-expanded (confirm with CXR). Option A requires CXR confirmation. Option C may not address the cause. Option D should come after troubleshooting.", "Chest Tube Management", "Troubleshooting", ["respiratory", "chest-tube", "troubleshooting", "assessment"], "Absent tidaling: check tubing for kinks/clamps first, then have patient cough. If tidaling returns = was mechanical issue. If no return = lung likely re-expanded (confirm with CXR)."),

  q("Respiratory", 2, "A nurse is teaching a client about pursed-lip breathing. This technique is most beneficial for clients with:", ["Asthma only", "COPD, as it prevents airway collapse during exhalation", "Pneumonia", "Pulmonary embolism"], 1, "Pursed-lip breathing creates back-pressure that splints the airways open during exhalation, preventing premature airway collapse (which occurs in COPD due to loss of elastic recoil). It prolongs exhalation time, improves gas exchange, and reduces air trapping. Technique: inhale through the nose for 2 counts, exhale through pursed lips for 4 counts. While beneficial for any dyspneic client, it is most specifically therapeutic for COPD.", "COPD", "Breathing Techniques", ["respiratory", "COPD", "pursed-lip-breathing", "patient-education"], "Pursed-lip breathing: inhale through nose (2 counts), exhale through pursed lips (4 counts). Prevents airway collapse in COPD. Also useful during activity or dyspnea episodes."),

  q("Respiratory", 4, "A client on a ventilator has the following ABG: pH 7.50, PaCO2 28, HCO3 22. The nurse should:", ["Increase the tidal volume", "Decrease the respiratory rate or tidal volume to correct respiratory alkalosis", "Add more PEEP", "Administer sodium bicarbonate"], 1, "pH >7.45 = alkalosis. PaCO2 <35 = respiratory cause (over-ventilation). HCO3 normal = uncompensated. This is respiratory alkalosis from excessive mechanical ventilation. Corrective action: decrease the minute ventilation by reducing respiratory rate or tidal volume. Option A would worsen alkalosis. Option C does not address the ventilation. Option D would worsen alkalosis.", "Mechanical Ventilation", "ABG-Based Adjustments", ["respiratory", "ABG", "ventilation", "respiratory-alkalosis"], "Ventilator-induced respiratory alkalosis: reduce minute ventilation (lower RR or TV). Respiratory acidosis: increase minute ventilation. Always correlate ABG with clinical status."),

  q("Respiratory", 3, "A nurse is preparing a client for a thoracentesis. Which assessment is most critical to perform immediately after the procedure?", ["Pain assessment", "Lung sounds on the affected side to assess for pneumothorax", "Blood glucose level", "Abdominal girth measurement"], 1, "Pneumothorax is the most significant complication of thoracentesis. After the procedure, the nurse should immediately auscultate lung sounds bilaterally, comparing the affected and unaffected sides. Diminished or absent breath sounds on the affected side may indicate pneumothorax. Also monitor respiratory rate, SpO2, and obtain a post-procedure chest X-ray as ordered. Options A, C, and D are not the priority assessment.", "Thoracentesis", "Post-Procedure Assessment", ["respiratory", "thoracentesis", "pneumothorax", "assessment"], "Post-thoracentesis: assess lung sounds immediately, monitor VS, obtain CXR. Signs of pneumothorax: sudden dyspnea, absent breath sounds, tachycardia. Max drainage: 1,000-1,500 mL to prevent re-expansion pulmonary edema."),

  q("Respiratory", 3, "A client with chronic bronchitis is described as a 'blue bloater.' The nurse understands this term refers to:", ["A client who is thin with a barrel chest", "A client who is overweight with chronic hypoxemia, cyanosis, peripheral edema, and productive cough", "A client with acute asthma", "A client with pulmonary fibrosis"], 1, "Blue bloater = chronic bronchitis: overweight, chronic productive cough, cyanosis from chronic hypoxemia, peripheral edema from cor pulmonale, polycythemia. Pink puffer = emphysema: thin, barrel chest, pursed-lip breathing, dyspnea with minimal sputum, pink complexion (maintains oxygenation until late disease). Option A describes a pink puffer. Options C and D are different conditions.", "COPD", "Clinical Phenotypes", ["respiratory", "COPD", "chronic-bronchitis", "assessment"], "COPD phenotypes: Blue bloater (chronic bronchitis) = cyanotic, edematous, productive cough. Pink puffer (emphysema) = thin, barrel chest, dyspneic, pursed-lip breathing. Most COPD patients have features of both."),

  q("Respiratory", 2, "A client is diagnosed with community-acquired pneumonia. The nurse expects the chest X-ray to show:", ["Bilateral clear lung fields", "Consolidation or infiltrates in the affected lobe", "Hyperinflation with flattened diaphragm", "Pleural thickening without infiltrates"], 1, "Pneumonia causes alveolar consolidation (fluid/exudate filling the air spaces), which appears as white opacities or infiltrates on CXR. Location can indicate the type: upper lobes are common in TB and aspiration (if posterior segments), lower lobes are common in typical CAP. Option A is normal. Option C is seen in COPD/emphysema. Option D suggests a different process.", "Pneumonia", "Diagnostic Findings", ["respiratory", "pneumonia", "CXR", "diagnostics"], "Pneumonia CXR: lobar consolidation (typical bacteria), diffuse bilateral infiltrates (atypical/viral/PJP), cavitation (TB, Staph, Klebsiella). Repeat CXR in 6-8 weeks to confirm resolution."),

  q("Respiratory", 3, "A client develops acute respiratory failure. Which ABG finding is consistent with this diagnosis?", ["pH 7.42, PaCO2 40, PaO2 95", "pH 7.25, PaCO2 65, PaO2 50", "pH 7.48, PaCO2 32, PaO2 98", "pH 7.40, PaCO2 38, PaO2 85"], 1, "Acute respiratory failure is defined as PaO2 <60 mmHg (hypoxemic failure, Type 1) and/or PaCO2 >50 mmHg with pH <7.35 (hypercapnic failure, Type 2). This ABG shows respiratory acidosis (pH 7.25, PaCO2 65) with hypoxemia (PaO2 50), consistent with combined Type 1 and Type 2 respiratory failure. Options A and D are normal. Option C shows respiratory alkalosis with normal oxygenation.", "Respiratory Failure", "ABG Interpretation", ["respiratory", "respiratory-failure", "ABG", "critical-care"], "Respiratory failure types: Type 1 (hypoxemic) = PaO2 <60 mmHg. Type 2 (hypercapnic) = PaCO2 >50 + acidosis. Type 1 treatment: supplemental O2. Type 2: ventilatory support (NIV or intubation)."),

  q("Respiratory", 3, "A nurse is caring for a client with a pulmonary contusion. The nurse should anticipate which respiratory complication?", ["Spontaneous pneumothorax", "ARDS developing 24-72 hours after the initial injury", "Chronic bronchitis", "Asthma exacerbation"], 1, "Pulmonary contusion causes hemorrhage and edema within the lung parenchyma. The initial injury triggers an inflammatory cascade that can progress to ARDS within 24-72 hours. Management includes careful fluid management (avoid fluid overload while maintaining perfusion), pain control, pulmonary hygiene, and respiratory monitoring. Serial CXR and ABGs are essential. Option A is not a direct consequence. Options C and D are chronic conditions.", "Chest Trauma", "Pulmonary Contusion", ["respiratory", "trauma", "pulmonary-contusion", "ARDS"], "Pulmonary contusion: develops over 24-72 hours. CXR may initially appear normal. Watch for deteriorating PaO2/FiO2 ratio. Judicious fluid management — avoid both overhydration and dehydration."),

  q("Respiratory", 2, "A nurse is teaching a client about incentive spirometry. The nurse should instruct the client to:", ["Inhale quickly through the mouthpiece", "Sit upright, exhale normally, then inhale slowly and deeply through the mouthpiece, holding the breath for 5-10 seconds at the peak", "Use it once daily", "Exhale forcefully into the device"], 1, "Proper incentive spirometry technique: sit upright (maximizes lung expansion), exhale normally, place mouthpiece in mouth, inhale slowly and deeply (sustained maximal inspiration), hold breath for 5-10 seconds, exhale normally, repeat 10 times per hour while awake. Goal: prevent atelectasis post-operatively. Option A does not promote sustained maximal inspiration. Option C is insufficient frequency. Option D is the wrong direction of airflow.", "Incentive Spirometry", "Technique", ["respiratory", "incentive-spirometry", "post-operative", "patient-education"], "Incentive spirometry: 10 reps/hour while awake. Sit upright. Inhale slowly. Hold 5-10 sec. Goal: prevent post-operative atelectasis. Most effective when combined with early ambulation."),

  // ============================================================
  // GI ADDITIONAL (25 questions)
  // ============================================================
  q("Gastrointestinal", 3, "A client with esophageal varices develops hematemesis. The nurse should prepare for:", ["Oral vitamin K administration", "Emergent endoscopy with variceal band ligation, IV octreotide, and blood product replacement", "Oral antacid therapy", "Scheduled colonoscopy"], 1, "Esophageal variceal bleeding is a life-threatening emergency in cirrhosis. Management: hemodynamic resuscitation (IV access, blood products), IV octreotide (reduces portal pressure), emergent endoscopy for band ligation or sclerotherapy, IV PPI, and possibly balloon tamponade (Blakemore tube) as a bridge. Option A is too slow and not first-line. Option C is ineffective for variceal bleeding. Option D assesses the colon, not esophagus.", "Cirrhosis", "Variceal Bleeding", ["GI", "varices", "cirrhosis", "emergency"], "Variceal bleed: IV octreotide + emergent endoscopy (band ligation). Blakemore tube as temporizing measure. Prophylaxis: non-selective beta-blocker (propranolol) or band ligation for medium-large varices."),

  q("Gastrointestinal", 2, "A client with a new ileostomy asks about expected output consistency. The nurse should explain:", ["Output will be formed like a normal bowel movement", "Output will be liquid to semi-liquid and contain digestive enzymes that can irritate the skin", "There will be no output for several days", "Output will be solid pellets"], 1, "Ileostomy output is liquid to semi-liquid because the colon (where water absorption primarily occurs) has been bypassed. The effluent contains active digestive enzymes that can cause severe peristomal skin breakdown. Proper skin barrier application is essential. Output is typically 500-800 mL/day. Monitor for dehydration and electrolyte imbalances. Options A and D describe colostomy output. Option C is incorrect unless there is an obstruction.", "Ileostomy", "Output Management", ["GI", "ileostomy", "ostomy-care", "patient-education"], "Ileostomy output: liquid, enzyme-rich (skin corrosive). Monitor fluid/electrolytes closely. Risk of dehydration and hypokalemia. Empty bag when 1/3 full. Skin barrier is critical for skin protection."),

  q("Gastrointestinal", 3, "A nurse is caring for a client with acute cholecystitis. The classic triad of symptoms includes:", ["Nausea, diarrhea, and weight loss", "Right upper quadrant pain, fever, and leukocytosis (Charcot's triad for cholangitis is pain, fever, and jaundice)", "Left lower quadrant pain, constipation, and bloating", "Epigastric pain, hematemesis, and melena"], 1, "Acute cholecystitis presents with: RUQ pain (especially after fatty meals), fever, and leukocytosis. Murphy's sign (inspiratory arrest during RUQ palpation) is characteristic. Charcot's triad (RUQ pain + fever + jaundice) specifically indicates cholangitis (bile duct infection). Reynolds' pentad adds altered mental status and shock. Option A is non-specific. Option C suggests diverticulitis. Option D suggests upper GI bleeding.", "Cholecystitis", "Clinical Presentation", ["GI", "cholecystitis", "assessment", "gallbladder"], "Cholecystitis: RUQ pain, fever, + Murphy's sign. Charcot's triad (cholangitis): pain + fever + jaundice. Reynolds' pentad: Charcot's triad + shock + AMS. Emergency cholecystectomy within 72 hrs."),

  q("Gastrointestinal", 3, "A client with a bowel obstruction has an NG tube on low intermittent suction. The nurse should monitor for:", ["Hyperkalemia and metabolic acidosis", "Metabolic alkalosis from loss of hydrogen and chloride ions", "Respiratory alkalosis", "No electrolyte changes"], 1, "NG suction removes gastric acid (HCl), leading to loss of hydrogen and chloride ions. This causes hypochloremic metabolic alkalosis and hypokalemia (as the kidneys excrete K+ to retain H+ in an attempt to correct the alkalosis). Monitor electrolytes closely and replace as ordered. Option A is the opposite. Option C is unrelated to NG suction. Option D ignores significant electrolyte shifts.", "Bowel Obstruction", "NG Suction Electrolytes", ["GI", "NG-tube", "electrolytes", "metabolic-alkalosis"], "NG suction losses: H+, Cl-, K+, Na+ = hypochloremic, hypokalemic metabolic alkalosis. Replace with IV NS + KCl. Monitor I&O carefully. Hold oral intake until obstruction resolves."),

  q("Gastrointestinal", 4, "A client with inflammatory bowel disease is started on infliximab (Remicade). The nurse should monitor for which serious adverse effect?", ["Hypoglycemia", "Reactivation of latent tuberculosis", "Hyperkalemia", "Hyperthyroidism"], 1, "Infliximab is a TNF-alpha inhibitor that suppresses immune function. A major risk is reactivation of latent TB, as TNF-alpha is critical for maintaining TB granulomas. ALL patients must be tested for latent TB (PPD or IGRA) before starting anti-TNF therapy. Other risks include serious infections, lymphoma, demyelinating disease, and infusion reactions. Options A, C, and D are not associated with infliximab.", "Inflammatory Bowel Disease", "Biologic Therapy", ["GI", "IBD", "infliximab", "immunosuppression"], "Anti-TNF therapy: screen for latent TB before starting (PPD or QuantiFERON). Screen for hepatitis B. Monitor for serious infections. Live vaccines contraindicated during therapy."),

  q("Gastrointestinal", 2, "A client is prescribed a clear liquid diet. Which food item is appropriate?", ["Milk", "Apple juice, gelatin, and broth", "Scrambled eggs", "Oatmeal"], 1, "Clear liquid diet includes foods that are liquid at room temperature and you can see through: clear broth, gelatin (Jell-O), clear juices without pulp (apple, cranberry, grape), popsicles, tea, coffee (no cream), and hard candy. Milk and opaque liquids are NOT clear liquids (they are full liquid diet). Options A (opaque), C (solid), and D (solid) are not clear liquids.", "Nutrition", "Diet Types", ["GI", "nutrition", "clear-liquid-diet", "post-operative"], "Clear liquid diet: see-through liquids only. Purpose: bowel rest, hydration, post-procedure. Full liquid: includes milk, cream soups, custard. Advance diet as tolerated: clear liquid → full liquid → soft → regular."),

  q("Gastrointestinal", 3, "A nurse is assessing a client with suspected peritonitis. Which finding is most indicative?", ["Hyperactive bowel sounds", "Rigid, board-like abdomen with rebound tenderness and absent bowel sounds", "Soft, non-tender abdomen", "Loud borborygmi"], 1, "Peritonitis presents with: rigid abdomen (involuntary guarding), board-like abdomen, rebound tenderness (pain with release of pressure), absent bowel sounds (paralytic ileus from inflammation), fever, tachycardia, and signs of sepsis. The rigid abdomen is the hallmark finding. Options A and D indicate bowel hyperactivity. Option C is a normal finding.", "Peritonitis", "Assessment Findings", ["GI", "peritonitis", "assessment", "emergency"], "Peritonitis: rigid board-like abdomen, rebound tenderness, absent bowel sounds, fever. Causes: perforated ulcer, ruptured appendix, diverticular perforation. Treatment: IV antibiotics, NPO, possible surgical repair."),

  q("Gastrointestinal", 3, "A client post-colostomy surgery is being taught about pouch care. The nurse should teach that the pouch should be emptied when it is:", ["Completely full", "One-third to one-half full to prevent leakage from weight of contents", "Only once per day", "Only when it causes discomfort"], 1, "The ostomy pouch should be emptied when it is approximately one-third to one-half full. A full or overfull pouch becomes heavy, pulling on the skin barrier and causing leakage and peristomal skin breakdown. Change the entire pouching system every 3-7 days or when the seal is compromised. Option A causes leakage. Option C is insufficient for most clients. Option D leads to complications.", "Colostomy", "Pouch Management", ["GI", "colostomy", "ostomy-care", "patient-education"], "Ostomy pouch: empty at 1/3 to 1/2 full. Change entire system every 3-7 days. Cut skin barrier to fit snugly around stoma (1/8 inch clearance). Assess stoma: should be beefy red and moist."),

  q("Gastrointestinal", 3, "A client with hepatic encephalopathy has an ammonia level of 145 mcg/dL. The nurse expects the client to exhibit:", ["No neurological changes", "Altered mental status, asterixis (flapping tremor), and confusion", "Improved cognitive function", "Only mild headache"], 1, "Normal serum ammonia is 15-45 mcg/dL. A level of 145 mcg/dL is significantly elevated, indicating that the liver cannot adequately metabolize ammonia. Ammonia is neurotoxic and causes: altered mental status, asterixis (liver flap), confusion, lethargy progressing to coma. Treatment: lactulose, rifaximin, protein restriction (in acute phase), treat precipitating factors. Option A ignores the severity. Options C and D underestimate the impact.", "Hepatic Encephalopathy", "Clinical Manifestations", ["GI", "hepatic-encephalopathy", "ammonia", "assessment"], "Hepatic encephalopathy stages: 1) mild confusion, 2) drowsiness/asterixis, 3) somnolence/marked confusion, 4) coma. Asterixis = flapping tremor when wrists are dorsiflexed. Test by having patient extend arms and dorsiflex wrists."),

  q("Gastrointestinal", 2, "A nurse is teaching a client about celiac disease management. Which grain is safe to consume?", ["Wheat", "Barley", "Quinoa", "Rye"], 2, "Celiac disease requires lifelong avoidance of gluten-containing grains: wheat, barley, rye, and some oats (unless certified gluten-free). Safe grains include quinoa, rice, corn, millet, amaranth, buckwheat, and certified gluten-free oats. Quinoa is a complete protein and excellent nutrient source. Options A, B, and D all contain gluten.", "Celiac Disease", "Gluten-Free Diet", ["GI", "celiac-disease", "nutrition", "gluten-free"], "Celiac disease safe grains: rice, corn, quinoa, millet, amaranth, buckwheat, certified GF oats. Hidden gluten: soy sauce, malt, communion wafers, some medications. Tissue transglutaminase (tTG-IgA) is the screening test."),

  // ============================================================
  // RENAL ADDITIONAL (20 questions)
  // ============================================================
  q("Renal/Urinary", 3, "A client receiving hemodialysis develops disequilibrium syndrome. The nurse should recognize this condition is caused by:", ["Allergic reaction to the dialyzer", "Rapid removal of urea from the blood creating an osmotic gradient that draws fluid into the brain", "Insufficient dialysis time", "Hypotension from fluid removal"], 2, "Dialysis disequilibrium syndrome occurs during or immediately after hemodialysis when urea is removed from the blood faster than from the brain. This osmotic gradient draws water into the brain cells, causing cerebral edema. Symptoms: headache, nausea, vomiting, restlessness, confusion, and in severe cases, seizures and coma. Prevention: shorter initial dialysis sessions with lower blood flow rates. Option A is a different complication. Option C is not the cause. Option D describes intradialytic hypotension.", "Hemodialysis", "Disequilibrium Syndrome", ["renal", "hemodialysis", "disequilibrium", "complications"], "Dialysis disequilibrium: more common in new dialysis patients. Prevent with slower initial treatments. Symptoms: headache, nausea, confusion, seizures. Treat: slow/stop dialysis, mannitol, hypertonic saline."),

  q("Renal/Urinary", 2, "A client with chronic kidney disease asks why phosphorus-binding medications must be taken with meals. The nurse should explain:", ["To prevent stomach upset", "The medication binds dietary phosphorus in the GI tract, preventing its absorption into the blood", "To improve the taste of food", "For better medication absorption"], 1, "Phosphate binders work by chemically binding phosphorus from food in the gastrointestinal tract, forming insoluble complexes that are excreted in the stool. If taken without food, the binders have no phosphorus to bind and are ineffective. This is a critical timing requirement. Options A, C, and D are not the mechanism of action.", "Chronic Kidney Disease", "Phosphate Binder Timing", ["renal", "CKD", "phosphorus", "medication-timing"], "Phosphate binder timing: MUST take WITH meals (binds food phosphorus). Types: calcium acetate, sevelamer (non-calcium), lanthanum. Dietary phosphorus restriction: avoid processed foods, cola, dairy."),

  q("Renal/Urinary", 3, "A nurse is caring for a client with a ureteral stent. The client reports frequency, urgency, and flank pain. The nurse should:", ["Remove the stent immediately", "Reassure the client that these symptoms are common with ureteral stents and administer prescribed analgesics", "Prepare for emergent surgery", "Restrict fluid intake"], 1, "Ureteral stents commonly cause irritative voiding symptoms (frequency, urgency, dysuria) and flank pain, especially during voiding (due to vesicoureteral reflux through the stent). These are expected side effects. Management includes adequate hydration, prescribed analgesics (NSAIDs, alpha-blockers like tamsulosin), and phenazopyridine for bladder discomfort. Option A is not indicated for expected symptoms. Option C overreacts. Option D is contraindicated.", "Urinary Procedures", "Ureteral Stent Management", ["renal", "ureteral-stent", "post-procedure", "patient-education"], "Ureteral stent symptoms: frequency, urgency, flank pain, hematuria — all common and expected. Tamsulosin may reduce stent-related symptoms. Stent removal typically 1-6 weeks post-procedure."),

  q("Renal/Urinary", 4, "A client with end-stage renal disease has a serum calcium of 7.2 mg/dL and a phosphorus of 7.8 mg/dL. The nurse understands the relationship is:", ["Unrelated", "Inverse — elevated phosphorus causes calcium to decrease because phosphorus binds with calcium, depositing in soft tissues", "Both should increase together", "Calcium levels are unaffected by kidney function"], 1, "Calcium and phosphorus have an inverse relationship. In CKD, the kidneys cannot excrete phosphorus, leading to hyperphosphatemia. Excess phosphorus binds with serum calcium, depositing calcium-phosphorus crystals in soft tissues (metastatic calcification) and lowering serum calcium. Additionally, damaged kidneys cannot activate vitamin D (calcitriol), further reducing calcium absorption. Options A, C, and D are incorrect.", "Chronic Kidney Disease", "Calcium-Phosphorus Balance", ["renal", "CKD", "calcium", "phosphorus"], "CKD mineral metabolism: high phosphorus + low calcium + low vitamin D + high PTH = renal osteodystrophy. Treatment: phosphate binders, calcitriol, calcimimetics (cinacalcet). Ca x P product should be < 55."),

  q("Renal/Urinary", 3, "A client with a nephrostomy tube has bloody drainage initially after placement. The nurse should:", ["Clamp the tube to stop the bleeding", "Monitor the drainage, which is expected to transition from bloody to serous over 24-48 hours", "Irrigate the tube aggressively", "Remove the tube"], 1, "Some bloody drainage from a nephrostomy tube is expected immediately after placement due to the procedure itself. The drainage should gradually clear from bloody to serosanguineous to serous over 24-48 hours. Persistent heavy bleeding warrants notification of the provider. NEVER clamp a nephrostomy tube (causes hydronephrosis and potential kidney damage). Never irrigate without a specific order. Options A, C, and D are incorrect actions.", "Nephrostomy", "Post-Procedure Care", ["renal", "nephrostomy", "post-procedure", "drainage"], "Nephrostomy tube: NEVER clamp (causes hydronephrosis). Expect bloody drainage initially. Tube is gravity drainage — keep below kidney level. Monitor UO from each kidney separately if bilateral."),

  q("Renal/Urinary", 2, "A nurse is educating a client about preventing urinary tract infections. Which instruction is most important?", ["Decrease fluid intake to concentrate urine", "Void frequently, do not hold urine, and wipe from front to back", "Use bubble baths for hygiene", "Wear tight-fitting synthetic underwear"], 1, "UTI prevention strategies: void frequently (every 2-3 hours, don't hold urine), wipe front to back (prevents fecal contamination of urethra), adequate fluid intake (2-3 L/day), void before and after sexual intercourse, avoid irritants (bubble baths, feminine sprays), wear cotton underwear, and avoid sitting in wet bathing suits. Options A, C, and D increase UTI risk.", "UTI Prevention", "Patient Education", ["renal", "UTI", "prevention", "patient-education"], "UTI prevention: front to back wiping, frequent voiding, void pre/post intercourse, adequate fluids, cotton underwear, avoid irritants. Cranberry may reduce E. coli adhesion but does not treat existing UTI."),

  // ============================================================
  // NEURO ADDITIONAL (20 questions)
  // ============================================================
  q("Neurological", 3, "A client with a brain tumor develops signs of increased intracranial pressure with a widening pulse pressure, bradycardia, and irregular respirations. The nurse recognizes this as:", ["Normal neurological finding", "Cushing's triad indicating brainstem herniation is imminent", "Cardiac tamponade", "Autonomic dysreflexia"], 1, "Cushing's triad (also called Cushing's response) consists of: hypertension with widening pulse pressure, bradycardia, and irregular respirations (Cheyne-Stokes or ataxic breathing). This is a late and ominous sign of increased ICP indicating brainstem compression and imminent herniation. This is a medical emergency requiring immediate intervention (hyperventilation, mannitol, possible surgical decompression). Option A is dangerously wrong. Option C has different signs. Option D occurs with SCI.", "Increased ICP", "Cushing's Triad", ["neuro", "ICP", "cushings-triad", "emergency"], "Cushing's triad: hypertension (widened pulse pressure) + bradycardia + irregular respirations = LATE sign of herniation. Intervene before this point. Early signs: headache, vomiting, papilledema, altered LOC."),

  q("Neurological", 3, "A client with epilepsy is prescribed phenytoin. The nurse should teach about which oral hygiene complication?", ["Tooth decay only", "Gingival hyperplasia requiring meticulous oral care and regular dental visits", "Dry mouth only", "No oral complications"], 1, "Phenytoin causes gingival hyperplasia (overgrowth of gum tissue) in approximately 50% of patients. This is dose-related and can be minimized with meticulous oral hygiene: brush and floss regularly, use a soft toothbrush, massage gums, and visit the dentist every 3-6 months. Severe cases may require gum surgery (gingivectomy). Options A and C are incomplete. Option D is incorrect.", "Seizure Disorders", "Phenytoin Side Effects", ["neuro", "phenytoin", "gingival-hyperplasia", "oral-care"], "Phenytoin side effects: gingival hyperplasia (50%), hirsutism, coarsening of facial features, nystagmus (first sign of toxicity), ataxia, Steven-Johnson syndrome (rare). Meticulous oral care essential."),

  q("Neurological", 4, "A nurse is caring for a client with Guillain-Barre syndrome. The most critical assessment is:", ["Muscle strength in the hands", "Respiratory function including vital capacity and ability to handle secretions", "Pain level", "Skin integrity"], 1, "Guillain-Barre syndrome (GBS) causes ascending paralysis that can rapidly progress to respiratory failure. Respiratory muscles (diaphragm, intercostals) may become paralyzed, requiring intubation and mechanical ventilation. Monitor: vital capacity (intubate if <15-20 mL/kg), negative inspiratory force (NIF), respiratory rate, oxygen saturation, and ability to cough and swallow. Peak weakness occurs 2-4 weeks after onset. Options A, C, and D are important but not as critical.", "Guillain-Barre Syndrome", "Respiratory Monitoring", ["neuro", "GBS", "respiratory", "ascending-paralysis"], "GBS respiratory monitoring: vital capacity q2-4h. Intubate if VC < 15-20 mL/kg or NIF > -20 cmH2O. 30% require mechanical ventilation. Treatment: IVIG or plasmapheresis. Corticosteroids are NOT effective."),

  q("Neurological", 3, "A client with a cervical spine injury at C6 has been stabilized. The nurse should expect this client to:", ["Have full arm and hand function", "Have use of wrist extensors but no hand function, and require assistance with many ADLs", "Be fully ventilator dependent", "Have normal lower extremity function"], 1, "C6 spinal cord injury preserves: deltoids, biceps, wrist extensors (can dorsiflex wrists). Lost: finger function (grip/release), triceps (weak), trunk and lower extremity function. These clients can often perform modified independent activities (feeding, grooming with adaptive equipment) but need assistance with transfers, bowel/bladder programs, and many ADLs. Option A would require C7-C8 intact. Option C occurs with C1-C3 injuries. Option D is incorrect for any cervical injury.", "Spinal Cord Injury", "Functional Level Assessment", ["neuro", "spinal-cord-injury", "rehabilitation", "C6-injury"], "SCI functional levels: C3-C4 = vent dependent, C5 = biceps (feed with setup), C6 = wrist extensors (modified independence with adaptive equipment), C7 = triceps (more independent), T1-T12 = paraplegia."),

  q("Neurological", 2, "A nurse is providing care for a client after a lumbar laminectomy. The nurse should:", ["Encourage the client to sit in a recliner immediately", "Log-roll the client when repositioning and assess for CSF leak at the incision site", "Allow the client to bend at the waist to pick up objects", "Place multiple pillows under the knees for comfort"], 1, "Post-laminectomy care: log-roll to maintain spinal alignment, assess the dressing for clear drainage (CSF leak — halo sign if present), monitor neurological function (motor/sensory in lower extremities, bladder function), and maintain flat or slightly elevated HOB. Avoid bending, twisting, and lifting for 6 weeks. Option A is premature. Option C stresses the surgical site. Option D can cause hip flexion contracture and DVT.", "Spinal Surgery", "Post-Operative Care", ["neuro", "laminectomy", "post-operative", "positioning"], "Post-laminectomy: log-roll, assess for CSF leak (clear drainage, positive glucose test on drainage), neuro checks q2-4h, no bending/twisting/lifting x 6 weeks. Report: new numbness, weakness, or urinary retention."),

  q("Neurological", 3, "A client with trigeminal neuralgia (tic douloureux) should be taught to avoid:", ["Sleeping on the affected side", "Stimulating trigger zones on the face such as by chewing, brushing teeth vigorously, or exposure to cold wind", "Taking prescribed carbamazepine", "Gentle face washing"], 1, "Trigeminal neuralgia causes excruciating, electric shock-like facial pain along the distribution of the trigeminal nerve (CN V). Pain is triggered by stimulating trigger zones: chewing, talking, touching the face, brushing teeth, exposure to wind or temperature changes, and shaving. Teaching includes: chew on the unaffected side, use lukewarm water, avoid drafts, use a soft toothbrush. First-line medication: carbamazepine. Option C is the treatment. Options A and D may be modified but not primary triggers.", "Trigeminal Neuralgia", "Trigger Avoidance", ["neuro", "trigeminal-neuralgia", "pain-management", "patient-education"], "Trigeminal neuralgia: CN V, #1 drug = carbamazepine. Avoid triggers: chewing, cold wind, face touching. Chew on unaffected side. Surgical options: microvascular decompression, gamma knife."),

  // ============================================================
  // ENDOCRINE ADDITIONAL (15 questions)
  // ============================================================
  q("Endocrine", 3, "A client with diabetes mellitus develops dawn phenomenon. The nurse should explain that this occurs because:", ["The client ate too much before bed", "Counter-regulatory hormones (growth hormone, cortisol) cause early morning hyperglycemia between 4-8 AM", "The insulin dose is too high at bedtime", "The client exercised too vigorously"], 1, "Dawn phenomenon is early morning hyperglycemia (4-8 AM) caused by the normal nocturnal surge of counter-regulatory hormones (growth hormone, cortisol, catecholamines) that increase hepatic glucose production. Management: increase or adjust evening/bedtime insulin. Somogyi effect is different — it involves nocturnal hypoglycemia followed by rebound hyperglycemia. Check 3 AM blood glucose to differentiate. Option A is not the mechanism. Option C describes Somogyi effect. Option D is unrelated.", "Diabetes Management", "Dawn Phenomenon", ["endocrine", "diabetes", "dawn-phenomenon", "blood-glucose"], "Dawn vs Somogyi: Dawn = no 3 AM hypoglycemia, treat by increasing PM insulin. Somogyi = 3 AM hypoglycemia followed by rebound hyperglycemia, treat by DECREASING PM insulin or adding a snack."),

  q("Endocrine", 2, "A client with type 2 diabetes is started on a sulfonylurea (glipizide). The nurse should teach the client that the main risk of this medication class is:", ["Weight loss", "Hypoglycemia, especially if meals are skipped", "Lactic acidosis", "Renal impairment"], 1, "Sulfonylureas (glipizide, glyburide, glimepiride) stimulate pancreatic beta cells to release insulin regardless of blood glucose level. This can cause hypoglycemia, particularly if meals are skipped, during excessive exercise, or with alcohol use. Other side effects include weight gain. Clients should carry a fast-acting glucose source. Option A — sulfonylureas cause weight gain, not loss. Option C is associated with metformin. Option D is not a primary concern.", "Oral Hypoglycemics", "Sulfonylurea Education", ["endocrine", "diabetes", "sulfonylurea", "hypoglycemia"], "Sulfonylureas: stimulate insulin release. Risk: hypoglycemia (carry glucose source). Weight gain common. Take before meals. Avoid alcohol. Elderly at higher risk for prolonged hypoglycemia."),

  q("Endocrine", 4, "A client with a history of medullary thyroid carcinoma should NOT be prescribed which diabetes medication?", ["Metformin", "GLP-1 receptor agonists (liraglutide, semaglutide) due to risk of thyroid C-cell tumors", "Insulin", "SGLT2 inhibitors"], 1, "GLP-1 receptor agonists (liraglutide, semaglutide, dulaglutide) carry a black box warning for thyroid C-cell tumors based on animal studies. They are contraindicated in patients with a personal or family history of medullary thyroid carcinoma (MTC) or Multiple Endocrine Neoplasia syndrome type 2 (MEN 2). Options A, C, and D do not carry this contraindication.", "Diabetes Medications", "GLP-1 Contraindications", ["endocrine", "diabetes", "GLP-1", "contraindications"], "GLP-1 agonists: black box warning for thyroid C-cell tumors. Contraindicated in MTC or MEN 2. Benefits: weight loss, cardiovascular protection. Side effects: nausea, pancreatitis risk."),

  q("Endocrine", 3, "A client with hyperparathyroidism has a serum calcium of 12.8 mg/dL. The nurse should monitor for:", ["Hypotension", "Cardiac dysrhythmias (shortened QT), constipation, muscle weakness, kidney stones, and altered mental status", "Hyperactive reflexes", "Diarrhea"], 1, "Hypercalcemia (normal Ca 8.5-10.5 mg/dL) affects multiple systems. Mnemonic: 'Stones, Bones, Groans, Moans, Psychiatric Overtones.' Stones = kidney stones, Bones = bone pain/fractures, Groans = constipation, Moans = muscle weakness/fatigue, Psychiatric = confusion/depression. Cardiac effects: shortened QT interval, bradycardia, heart block. Option A — hypercalcemia causes hypertension. Option C — reflexes are decreased. Option D — constipation is characteristic.", "Hyperparathyroidism", "Hypercalcemia", ["endocrine", "calcium", "hyperparathyroidism", "electrolytes"], "Hypercalcemia: Stones, Bones, Groans, Moans, Psychiatric Overtones. ECG: shortened QT. Treatment: IV NS hydration, loop diuretics (furosemide), calcitonin, bisphosphonates, dialysis in severe cases."),

  q("Endocrine", 3, "A nurse is caring for a client with Graves' disease. The nurse observes exophthalmos (protruding eyes). Nursing care includes:", ["No special eye care needed", "Artificial tears, sunglasses for photophobia, elevate HOB during sleep, and tape eyelids closed at night if needed", "Applying ice packs to the eyes", "Restricting the client's fluid intake"], 1, "Exophthalmos in Graves' disease results from autoimmune infiltration of the retro-orbital tissues. Eye care: artificial tears/lubricating drops to prevent corneal drying, sunglasses for photophobia, elevate HOB to reduce periorbital edema, tape eyelids closed during sleep if they cannot close fully, and report eye pain or vision changes. Exophthalmos may not resolve with treatment of hyperthyroidism. Options A, C, and D are not appropriate interventions.", "Hyperthyroidism", "Exophthalmos Care", ["endocrine", "graves-disease", "exophthalmos", "eye-care"], "Graves' exophthalmos: may persist even after hyperthyroidism is treated. Severe cases may need orbital decompression surgery. Protect eyes: artificial tears, sunglasses, HOB elevation, moisture chambers at night."),

  // ============================================================
  // PHARMACOLOGY ADDITIONAL (100+ questions)
  // ============================================================
  q("Pharmacology", 3, "A client is prescribed metoprolol. Before administering, the nurse should assess:", ["Blood glucose level", "Heart rate and blood pressure; hold if HR < 60 or SBP < 90", "Serum potassium", "Respiratory rate only"], 1, "Beta-blockers (metoprolol, atenolol, propranolol) decrease heart rate and blood pressure. Assessment before administration: apical heart rate for 60 seconds (hold if <60 bpm), blood pressure (hold if SBP <90 mmHg). Also assess for signs of heart failure (crackles, edema, weight gain) and bronchospasm in asthma/COPD patients (non-selective beta-blockers). Option A is for insulin. Option C is for ACE inhibitors. Option D is incomplete.", "Beta-Blockers", "Pre-Administration Assessment", ["pharmacology", "beta-blockers", "metoprolol", "vital-signs"], "Beta-blocker assessment: HR and BP before every dose. Hold if HR <60 or SBP <90. Never stop abruptly (rebound tachycardia, HTN, angina). Teach client to check pulse daily."),

  q("Pharmacology", 2, "A nurse is teaching a client about the medication alendronate (Fosamax). Which instruction is essential?", ["Take with coffee in the morning", "Take first thing in the morning on an empty stomach with a full glass of plain water and remain upright for at least 30 minutes", "Take at bedtime with a snack", "Crush the tablet for easier swallowing"], 1, "Bisphosphonate administration: first thing in the morning, empty stomach, full glass (8 oz) PLAIN water (not juice, coffee, or mineral water), remain upright (sitting or standing) for 30 minutes, no food/drink/other medications for 30 minutes. This prevents esophageal ulceration. Do NOT crush, chew, or suck the tablet. Option A — coffee reduces absorption. Option C risks esophageal damage. Option D can cause esophageal irritation.", "Bisphosphonates", "Administration Guidelines", ["pharmacology", "bisphosphonates", "osteoporosis", "medication-safety"], "Bisphosphonate esophageal protection: upright 30 min, plain water only, empty stomach. If unable to remain upright, consider IV bisphosphonate (zoledronic acid) or denosumab injection."),

  q("Pharmacology", 3, "A client is prescribed potassium chloride (KCl) oral supplement. The nurse should advise:", ["Swallow the tablet whole on an empty stomach", "Take with food and a full glass of water to reduce GI irritation", "Crush the extended-release tablet for easier administration", "Take it at bedtime without water"], 1, "Oral KCl can cause significant GI irritation, including nausea, vomiting, and ulceration. Taking it with food and a full glass of water (8 oz) reduces GI side effects. Extended-release formulations should NEVER be crushed (causes dumping of the entire dose, risking GI ulceration and hyperkalemia). Monitor serum potassium levels. Option A increases GI irritation. Option C is dangerous. Option D increases GI side effects.", "Electrolyte Supplements", "Oral KCl Administration", ["pharmacology", "potassium", "oral-supplementation", "GI-safety"], "Oral KCl: with food + full glass of water. Never crush extended-release. Liquid KCl: dilute in juice and use a straw (bad taste). Monitor K+ levels. Report: nausea, vomiting, abdominal pain, black stools."),

  q("Pharmacology", 3, "A client taking carbamazepine for seizures develops a rash. The nurse should:", ["Apply topical hydrocortisone and continue the medication", "Stop the medication and notify the provider immediately as this may indicate Stevens-Johnson syndrome", "Monitor the rash and continue the medication", "Increase fluid intake to flush the medication"], 1, "Carbamazepine carries a risk of Stevens-Johnson syndrome (SJS) and toxic epidermal necrolysis (TEN) — life-threatening skin reactions. Any rash during carbamazepine therapy must be taken seriously. The medication should be stopped and the provider notified immediately. HLA-B*1502 allele (more common in Asian populations) increases SJS risk — genetic testing is recommended before starting carbamazepine. Options A, C, and D delay critical intervention.", "Anticonvulsants", "Stevens-Johnson Syndrome", ["pharmacology", "carbamazepine", "SJS", "adverse-effects"], "Carbamazepine rash: STOP immediately. SJS/TEN can be fatal. Test HLA-B*1502 before starting (especially Asian patients). Also monitor CBC (aplastic anemia risk), LFTs, and serum levels (therapeutic 4-12 mcg/mL)."),

  q("Pharmacology", 2, "A client prescribed ondansetron (Zofran) for nausea asks how the medication works. The nurse explains:", ["It stimulates the vomiting center", "It blocks serotonin receptors in the chemoreceptor trigger zone and GI tract, preventing nausea and vomiting", "It is an antihistamine", "It coats the stomach lining"], 1, "Ondansetron is a 5-HT3 (serotonin) receptor antagonist. It blocks serotonin receptors in the chemoreceptor trigger zone (CTZ) and vagal nerve terminals in the GI tract, preventing nausea and vomiting signals from reaching the vomiting center. Commonly used for chemotherapy-induced, postoperative, and radiation-induced nausea. Side effects include headache, constipation, and QT prolongation. Options A, C, and D are incorrect mechanisms.", "Antiemetics", "Ondansetron Mechanism", ["pharmacology", "ondansetron", "antiemetic", "mechanism"], "Ondansetron: 5-HT3 antagonist. Monitor for QT prolongation (ECG before administration in high-risk patients). Can cause constipation and headache. Available PO, IV, and ODT (orally disintegrating tablet)."),

  q("Pharmacology", 3, "A nurse is administering dopamine through a peripheral IV. The nurse notices blanching and swelling around the IV site. The nurse should:", ["Continue the infusion and monitor", "Stop the infusion immediately and prepare to administer phentolamine (Regitine) into the affected area", "Increase the infusion rate", "Apply ice to the area"], 1, "Dopamine is a vesicant — extravasation causes severe local tissue ischemia and necrosis due to vasoconstriction. Treatment: immediately stop the infusion, leave the catheter in place, aspirate as much drug as possible, inject phentolamine (alpha-adrenergic blocker) 5-10 mg in 10-15 mL NS subcutaneously around the affected area to reverse vasoconstriction. Central venous access is preferred for vasopressors. Option A delays treatment. Option C worsens extravasation. Option D worsens vasoconstriction.", "Vasopressors", "Extravasation Management", ["pharmacology", "dopamine", "extravasation", "medication-safety"], "Vasopressor extravasation: stop infusion, aspirate, inject phentolamine SC into affected area. Prevention: use central line for vasopressors. Phentolamine reverses alpha-mediated vasoconstriction. Document and photograph the site."),

  q("Pharmacology", 3, "A client is prescribed azithromycin (Zithromax). The nurse should teach the client to report:", ["Improved appetite", "Hearing changes, dizziness, or irregular heartbeat (QT prolongation risk)", "Mild headache", "Increased energy"], 1, "Azithromycin can cause QT prolongation (risk of torsades de pointes), ototoxicity (hearing loss, tinnitus, vertigo — usually reversible), and hepatotoxicity. It should be used cautiously in patients with existing QT prolongation, hypokalemia, or concurrent QT-prolonging drugs. GI side effects (nausea, diarrhea, abdominal pain) are common. Options A, C, and D are not concerning findings.", "Antibiotics", "Azithromycin Monitoring", ["pharmacology", "azithromycin", "QT-prolongation", "adverse-effects"], "Azithromycin risks: QT prolongation (ECG in high-risk patients), ototoxicity, hepatotoxicity. GI side effects common. Z-pack (5-day course) is popular but contributes to antibiotic resistance when overused."),

  q("Pharmacology", 2, "A client is prescribed ferrous sulfate for iron deficiency anemia. The nurse should teach:", ["Take with milk for better tolerance", "Take on an empty stomach with vitamin C; expect dark/black stools", "Take with calcium supplements", "Stools should remain normal in color"], 1, "Iron supplementation teaching: take on empty stomach (1 hr before or 2 hrs after meals) for maximum absorption. Vitamin C (orange juice) enhances absorption. EXPECT dark/black stools (normal side effect — not blood). Liquid iron: use a straw to prevent tooth staining. Avoid concurrent calcium, antacids, and dairy. Options A and C interfere with absorption. Option D is incorrect.", "Iron Supplementation", "Patient Teaching", ["pharmacology", "iron", "anemia", "patient-education"], "Iron teaching: empty stomach, vitamin C for absorption, expect black stools, liquid = straw (teeth staining). Separate from calcium, antacids, dairy, tea, coffee by 2+ hours. Constipation common — increase fiber/fluids."),

  q("Pharmacology", 4, "A client on warfarin therapy requires a dental extraction. The nurse should advise:", ["Stop warfarin 1 week before the procedure", "Consult with the prescribing provider; warfarin may need to be temporarily held or bridged with heparin depending on thromboembolic risk", "Continue warfarin without any modification", "Switch to aspirin permanently"], 1, "Warfarin management for procedures requires balancing bleeding risk against thromboembolic risk. Low-risk patients may have warfarin held for 5 days pre-procedure. High-risk patients (mechanical heart valve, recent VTE) may require bridging with LMWH or heparin. Some minor dental procedures can be performed with an INR <3.0 using local hemostatic measures. The decision must be made by the prescribing provider. Option A may be too long. Option C risks bleeding. Option D is not standard.", "Anticoagulant Therapy", "Perioperative Management", ["pharmacology", "warfarin", "perioperative", "dental"], "Warfarin perioperative: 5-day hold for most procedures (INR normalizes). Bridge with LMWH if high thromboembolic risk. Low-risk dental: may continue with INR <3.0 and local hemostatic measures."),

  q("Pharmacology", 3, "A client is receiving propofol (Diprivan) for sedation in the ICU. The nurse should monitor for:", ["Hyperglycemia", "Hypertriglyceridemia and propofol infusion syndrome (monitor triglycerides and CK)", "Hypernatremia", "Metabolic alkalosis"], 1, "Propofol is formulated in a lipid emulsion (soybean oil), contributing calories and raising triglycerides. Propofol infusion syndrome (PRIS) is a rare but fatal complication of prolonged, high-dose infusion: metabolic acidosis, rhabdomyolysis, hyperkalemia, cardiac failure. Monitor triglycerides every 24-48 hours, CK levels, and limit infusion to <4 mg/kg/hr. Option A is not the primary concern. Options C and D are not propofol-related.", "Sedation", "Propofol Monitoring", ["pharmacology", "propofol", "critical-care", "PRIS"], "Propofol: lipid-based (count calories from lipid emulsion). Change tubing every 12 hrs (infection risk). PRIS: metabolic acidosis, rhabdomyolysis, cardiac failure. Limit to <4 mg/kg/hr and <48 hrs if possible."),

  q("Pharmacology", 2, "A nurse is teaching a client about the calcium channel blocker verapamil. Which food interaction should be discussed?", ["Tyramine-rich foods", "Grapefruit juice, which significantly increases verapamil blood levels", "Vitamin K-rich foods", "High-protein meals"], 1, "Grapefruit juice inhibits intestinal CYP3A4 enzymes, dramatically increasing the bioavailability of verapamil (and many other CCBs). This can cause severe hypotension, bradycardia, and heart block. Even small amounts of grapefruit juice can have significant effects, and the interaction persists for up to 72 hours. Options A (MAOI interaction), C (warfarin interaction), and D are not verapamil-related.", "Calcium Channel Blockers", "Drug-Food Interactions", ["pharmacology", "verapamil", "grapefruit", "drug-interactions"], "Verapamil + grapefruit: avoid completely. Non-dihydropyridine CCBs (verapamil, diltiazem) also slow HR — do not combine with beta-blockers (risk of severe bradycardia and heart block)."),

  q("Pharmacology", 3, "A client with heart failure is prescribed hydralazine and isosorbide dinitrate (BiDil). The nurse should explain this combination is particularly beneficial for:", ["All patients with heart failure equally", "African American patients with NYHA class III-IV heart failure who remain symptomatic on standard therapy", "Only elderly patients", "Patients with mild heart failure only"], 1, "The combination of hydralazine and isosorbide dinitrate has demonstrated significant mortality benefit specifically in African American patients with moderate-to-severe heart failure (A-HeFT trial). It is recommended as add-on therapy for African American patients with NYHA class III-IV symptoms despite optimal standard therapy (ACE inhibitor/ARB, beta-blocker, diuretic). Options A, C, and D are incorrect or overly broad.", "Heart Failure", "Race-Based Pharmacotherapy", ["pharmacology", "heart-failure", "hydralazine", "BiDil"], "BiDil (hydralazine + isosorbide dinitrate): specific evidence in African American patients with HFrEF. Reduces mortality by 43%. Also used as ACE/ARB alternative in patients intolerant to those medications."),

  q("Pharmacology", 3, "A client receiving IV aminophylline develops a heart rate of 140 bpm and is tremulous. The serum theophylline level is 25 mcg/mL. The nurse should:", ["Continue the infusion", "Stop the infusion and notify the provider — the level is toxic", "Increase the infusion rate", "Administer a beta-blocker"], 1, "Theophylline therapeutic range is 10-20 mcg/mL. A level of 25 mcg/mL is toxic. Signs of toxicity: tachycardia, tremors, nausea, vomiting, restlessness, seizures, and cardiac dysrhythmias. The infusion must be stopped immediately. Factors that increase levels: liver disease, heart failure, concurrent macrolides/fluoroquinolones, and cimetidine. Options A and C worsen toxicity. Option D may be premature without provider guidance.", "Methylxanthines", "Theophylline Toxicity", ["pharmacology", "theophylline", "toxicity", "bronchodilator"], "Theophylline: therapeutic 10-20 mcg/mL, narrow therapeutic window. Toxicity signs: tachycardia, tremors, seizures. Many drug interactions. Cigarette smoking decreases levels (induces CYP1A2)."),

  q("Pharmacology", 3, "A client is prescribed tamsulosin (Flomax) for benign prostatic hyperplasia. The nurse should warn about:", ["Hyperglycemia", "Orthostatic hypotension, especially with the first dose, and retrograde ejaculation", "Weight gain", "Hypertension"], 1, "Tamsulosin is an alpha-1 adrenergic blocker that relaxes smooth muscle in the prostate and bladder neck. Side effects include orthostatic hypotension (first-dose phenomenon — take at bedtime), dizziness, retrograde ejaculation, nasal congestion, and intraoperative floppy iris syndrome (notify ophthalmologist before cataract surgery). Options A, C, and D are not primary concerns.", "Alpha-Blockers", "BPH Treatment", ["pharmacology", "tamsulosin", "BPH", "orthostatic-hypotension"], "Tamsulosin: take at bedtime after a meal (reduces first-dose hypotension). Inform ophthalmologist before cataract surgery (floppy iris syndrome). Retrograde ejaculation is common but harmless."),

  q("Pharmacology", 2, "A nurse is educating a client about the proton pump inhibitor pantoprazole. Long-term risks include:", ["Hyperkalemia", "C. difficile infection, bone fractures, hypomagnesemia, and vitamin B12 deficiency", "Hyperglycemia", "Hepatic failure"], 1, "Long-term PPI use (>1 year) is associated with: C. difficile infection (reduced gastric acid allows bacterial survival), bone fractures (reduced calcium absorption), hypomagnesemia, vitamin B12 deficiency (acid needed for B12 absorption), kidney disease, and community-acquired pneumonia. PPIs should be used at the lowest effective dose for the shortest duration. Options A, C, and D are not primary long-term PPI risks.", "Proton Pump Inhibitors", "Long-Term Risks", ["pharmacology", "PPI", "pantoprazole", "long-term-effects"], "PPI long-term risks: C. diff, fractures (hip/spine/wrist), hypomagnesemia, B12 deficiency, CKD, CAP. Step-down to H2 blocker when possible. Annual review of necessity."),

  q("Pharmacology", 3, "A client is prescribed sucralfate (Carafate) for a gastric ulcer. The nurse should instruct:", ["Take with meals and other medications", "Take on an empty stomach 1 hour before meals; separate from other medications by 2 hours", "Take at bedtime only", "Take with antacids for enhanced effect"], 1, "Sucralfate forms a protective barrier over the ulcer crater by binding to positively charged proteins in the ulcer base. It must be taken on an empty stomach (1 hour before meals) to bind to the ulcer before food arrives. It can bind to other medications, reducing their absorption, so separate by 2 hours. Avoid antacids within 30 minutes (alter pH and reduce effectiveness). Option A reduces effectiveness. Option C is incomplete. Option D impairs its action.", "GI Protectants", "Sucralfate Administration", ["pharmacology", "sucralfate", "peptic-ulcer", "medication-timing"], "Sucralfate: coats ulcer crater. Empty stomach, 1 hr before meals, separate from other meds by 2 hrs. Does not reduce acid — protects the ulcer surface. Requires acidic environment to work (avoid antacids within 30 min)."),

  q("Pharmacology", 3, "A client is started on an ACE inhibitor and develops angioedema of the lips and tongue. The nurse should:", ["Administer diphenhydramine and observe", "Discontinue the ACE inhibitor permanently, maintain airway, and administer epinephrine if severe", "Switch to a different ACE inhibitor", "Continue the medication at a lower dose"], 1, "ACE inhibitor-induced angioedema is potentially life-threatening. It involves swelling of the face, lips, tongue, and larynx due to bradykinin accumulation. Management: permanently discontinue the ACE inhibitor (it occurs with ALL ACE inhibitors, so switching within the class is NOT safe), secure the airway, and administer epinephrine if airway compromise is present. An ARB may be cautiously considered as an alternative (small cross-reactivity risk). Option A is insufficient. Option C is dangerous. Option D risks recurrence.", "ACE Inhibitors", "Angioedema", ["pharmacology", "ACE-inhibitors", "angioedema", "emergency"], "ACE inhibitor angioedema: occurs in 0.1-0.7% of patients, more common in African Americans. Can occur at ANY time during therapy (even after years). Discontinue ALL ACE inhibitors permanently. ARBs: cautious alternative (1-2% cross-reactivity)."),

  q("Pharmacology", 2, "A client is prescribed colchicine for an acute gout flare. The nurse should teach:", ["Take large doses until pain resolves", "Take as prescribed; report severe GI symptoms (nausea, vomiting, diarrhea) as these indicate the need to reduce dose or stop", "This medication prevents future gout attacks", "Take with alcohol for better absorption"], 1, "Colchicine treats acute gout by inhibiting neutrophil migration and phagocytosis. The most common side effects are GI: nausea, vomiting, diarrhea, and abdominal cramping. These symptoms indicate the medication should be reduced or stopped. Severe toxicity includes bone marrow suppression and multi-organ failure. Modern dosing uses lower doses (1.2 mg then 0.6 mg 1 hour later) rather than traditional high-dose protocols. Option A risks toxicity. Option C — colchicine is for acute attacks, not prevention. Option D — avoid alcohol (worsens gout).", "Antigout Agents", "Colchicine Education", ["pharmacology", "colchicine", "gout", "adverse-effects"], "Colchicine acute gout: low-dose protocol (1.2 mg then 0.6 mg 1 hour later). GI symptoms = dose limit reached. Drug interactions with CYP3A4 inhibitors (clarithromycin) can cause fatal toxicity. Do NOT combine with grapefruit."),

  q("Pharmacology", 3, "A client receiving TPN develops fever, chills, and the TPN solution appears cloudy. The nurse should:", ["Continue the infusion and monitor", "Stop the TPN infusion immediately, maintain IV access, obtain blood cultures, and notify the provider", "Increase the infusion rate to finish the bag quickly", "Add antibiotics to the TPN bag"], 1, "Fever, chills, and cloudy TPN solution suggest contamination and possible catheter-related bloodstream infection (CRBSI). The nurse should immediately stop the TPN, save the bag for culture, draw peripheral and central line blood cultures, maintain IV access with a different solution, and notify the provider. CRBSI is a serious complication of central line TPN. Option A risks sepsis. Option C worsens the situation. Option D is not standard practice.", "TPN", "Infection Management", ["pharmacology", "TPN", "CRBSI", "infection"], "TPN infection signs: fever, chills, cloudy solution. Stop TPN, culture blood (peripheral + central), notify provider. Prevention: strict aseptic technique, dedicated TPN lumen, change tubing per protocol."),

  q("Pharmacology", 3, "A client with atrial fibrillation is prescribed diltiazem for rate control. The nurse should monitor for:", ["Hyperglycemia", "Bradycardia, hypotension, and constipation", "Tachycardia", "Hyperkalemia"], 1, "Diltiazem is a non-dihydropyridine calcium channel blocker that slows conduction through the AV node (rate control in AFib) and causes vasodilation. Adverse effects: bradycardia (assess HR before administration), hypotension, constipation (common with verapamil), peripheral edema, and dizziness. Do not combine with beta-blockers without careful monitoring (risk of severe bradycardia/heart block). Options A, C, and D are not diltiazem effects.", "Calcium Channel Blockers", "Diltiazem Monitoring", ["pharmacology", "diltiazem", "rate-control", "AFib"], "Diltiazem: assess HR and BP before each dose. Hold if HR <60 or SBP <90. Avoid combining with beta-blockers (severe bradycardia risk). IV diltiazem for acute AFib rate control, then transition to oral."),

  q("Pharmacology", 3, "A client is receiving IV mannitol for increased intracranial pressure. The nurse should monitor for:", ["Hyperkalemia", "Rebound increased ICP, fluid and electrolyte imbalances, and acute kidney injury from osmotic nephropathy", "Constipation", "Hyperglycemia"], 1, "Mannitol is an osmotic diuretic used to reduce ICP. Complications: rebound increased ICP (as mannitol eventually crosses the BBB), fluid and electrolyte imbalances (hyponatremia or hypernatremia, hypokalemia), acute kidney injury from osmotic nephropathy (monitor serum osmolality — hold if >320 mOsm/kg), and fluid overload in the initial distribution phase. Use an inline filter (may crystallize). Options A, C, and D are not primary mannitol concerns.", "Osmotic Diuretics", "Mannitol Monitoring", ["pharmacology", "mannitol", "ICP", "critical-care"], "Mannitol: use inline filter, monitor serum osmolality (hold if >320), monitor I&O, watch for rebound ICP. Alternative: hypertonic saline (3% NaCl) — does not have rebound effect."),

  q("Pharmacology", 2, "A nurse is preparing to administer erythropoietin (epoetin alfa) to a client with CKD-related anemia. The nurse should ensure:", ["Hemoglobin is below 7 g/dL before starting", "Iron stores are adequate before starting therapy, as epoetin requires iron for effective red blood cell production", "The medication is shaken vigorously before injection", "The client has normal renal function"], 1, "Erythropoietin (EPO) stimulates red blood cell production in the bone marrow, but iron is essential as a building block for hemoglobin. If iron stores are depleted (low ferritin, low transferrin saturation), EPO will be ineffective despite adequate dosing. Check iron studies before and during therapy. Target hemoglobin: 10-12 g/dL (do not exceed — increases cardiovascular risk). Option A — start before Hgb drops that low. Option C — do NOT shake (denatures protein). Option D is incorrect.", "Erythropoietin", "Pre-Treatment Assessment", ["pharmacology", "erythropoietin", "CKD", "anemia"], "EPO therapy: check iron stores first (ferritin >100, TSAT >20%). Target Hgb 10-12 g/dL (not >12 — increased CVD/stroke risk). Do not shake vial. SC injection preferred in CKD. Monitor BP (can cause hypertension)."),

  q("Pharmacology", 3, "A client on long-term corticosteroid therapy should be monitored for:", ["Hypoglycemia and weight loss", "Osteoporosis, hyperglycemia, immunosuppression, cataracts, and adrenal suppression", "Improved wound healing", "Decreased appetite"], 1, "Long-term corticosteroid effects are extensive: metabolic (hyperglycemia, hyperlipidemia), musculoskeletal (osteoporosis, muscle wasting, avascular necrosis), immunologic (infection risk, impaired wound healing), dermatologic (thin skin, bruising, striae), ophthalmologic (cataracts, glaucoma), endocrine (Cushing's features, adrenal suppression), psychiatric (mood changes, insomnia), and GI (peptic ulcers). Option A shows the opposite effects. Options C and D are incorrect.", "Corticosteroids", "Long-Term Side Effects", ["pharmacology", "corticosteroids", "osteoporosis", "long-term-effects"], "Long-term steroid monitoring: bone density (DEXA scan), blood glucose, eye exams (cataracts/glaucoma), BP, weight, infection screening. Prevention: calcium + vitamin D, bisphosphonates if indicated, lowest effective dose."),

  q("Pharmacology", 3, "A client is prescribed cephalexin and reports a penicillin allergy with hives. The nurse should:", ["Administer without concern as there is no cross-reactivity", "Notify the provider as there is approximately 1-2% cross-reactivity between penicillins and cephalosporins", "Administer with diphenhydramine premedication", "Switch to a macrolide antibiotic independently"], 1, "Cross-reactivity between penicillins and cephalosporins is approximately 1-2% (lower than previously thought at 10%). However, if the penicillin allergy involved a severe reaction (anaphylaxis, SJS), cephalosporins should generally be avoided. For mild reactions (hives, rash), cephalosporins can often be used with caution. The nurse should notify the provider to make this clinical decision. Options A ignores the allergy. Option C is nurse-independent decision. Option D is outside nursing scope.", "Antibiotics", "Cross-Reactivity", ["pharmacology", "cephalosporin", "penicillin-allergy", "drug-allergy"], "Penicillin-cephalosporin cross-reactivity: ~1-2% (NOT 10% as previously taught). Higher risk with 1st-generation cephalosporins. If penicillin reaction was anaphylaxis, avoid cephalosporins. Always verify allergy details (what happened, when)."),

  q("Pharmacology", 3, "A client is prescribed nitrofurantoin for a urinary tract infection. The nurse should advise:", ["Take on an empty stomach", "Take with food to increase absorption and reduce GI side effects; urine may turn brown or rust-colored", "Avoid all fluids while taking this medication", "This medication treats systemic infections"], 1, "Nitrofurantoin should be taken with food or milk to increase absorption and decrease GI side effects (nausea). Expected finding: urine may turn brown/rust/orange color. Nitrofurantoin is only effective for uncomplicated lower UTIs (it concentrates in urine, not in tissues or blood). Contraindicated with CrCl <30 mL/min (inadequate urinary concentration). Option A reduces absorption. Option C is incorrect. Option D is wrong — it only treats UTIs.", "Antibiotics", "Nitrofurantoin Education", ["pharmacology", "nitrofurantoin", "UTI", "patient-education"], "Nitrofurantoin: take with food, expect brown/rust urine. Only for lower UTIs (no systemic penetration). Contraindicated: CrCl <30 mL/min. Long-term use: monitor for pulmonary fibrosis and peripheral neuropathy."),

  q("Pharmacology", 2, "A nurse is administering IV antibiotics through a PICC line. Before and after administration, the nurse should:", ["Do nothing — the PICC is always ready to use", "Flush the line with normal saline before and after medication administration per protocol", "Use heparin flush before every medication", "Clamp the line during medication infusion"], 1, "PICC line maintenance includes flushing with normal saline (typically 10-20 mL) before and after medication administration and after blood draws. This ensures patency and prevents drug incompatibility reactions. Heparin flushes may be used for intermittent access lines (per facility protocol). Use pulsatile (push-pause) flushing technique. Assess the site for signs of infection, phlebitis, or infiltration. Option A leads to occlusion. Option C is not always required. Option D prevents medication delivery.", "IV Therapy", "PICC Line Management", ["pharmacology", "PICC", "IV-therapy", "line-management"], "PICC line care: NS flush before/after meds and blood draws. Heparin lock per protocol. Assess site daily: redness, swelling, drainage, tenderness. Dressing change weekly (transparent) or when soiled. Measure arm circumference to detect DVT."),

  q("Pharmacology", 3, "A client is prescribed dantrolene for malignant hyperthermia. The nurse understands this medication works by:", ["Blocking acetylcholine receptors", "Inhibiting calcium release from the sarcoplasmic reticulum, stopping uncontrolled muscle contraction and heat generation", "Stimulating the vagus nerve", "Blocking potassium channels"], 1, "Malignant hyperthermia (MH) is a life-threatening genetic condition triggered by volatile anesthetics and succinylcholine. Dantrolene sodium is the specific antidote — it directly acts on skeletal muscle to inhibit calcium release from the sarcoplasmic reticulum, stopping the hypermetabolic cascade. Initial dose: 2.5 mg/kg IV bolus, repeated up to 10 mg/kg. Also: active cooling, manage hyperkalemia and acidosis. Options A, C, and D are incorrect mechanisms.", "Emergency Medications", "Dantrolene", ["pharmacology", "dantrolene", "malignant-hyperthermia", "emergency"], "Malignant hyperthermia: earliest sign = unexplained rise in end-tidal CO2. Then: tachycardia, muscle rigidity, hyperthermia. Treatment: stop triggering agents, dantrolene 2.5 mg/kg IV, active cooling, manage hyperkalemia/acidosis."),
];

async function main() {
  let inserted = 0;
  const batchSize = 50;
  for (let i = 0; i < QS.length; i += batchSize) {
    const batch = QS.slice(i, i + batchSize);
    const values: string[] = [];
    const params: any[] = [];
    let idx = 1;
    for (const item of batch) {
      values.push(`($${idx},$${idx+1},$${idx+2},$${idx+3},$${idx+4},$${idx+5}::jsonb,$${idx+6}::jsonb,$${idx+7},$${idx+8}::integer,$${idx+9},$${idx+10},$${idx+11},$${idx+12},$${idx+13},$${idx+14}::text[],$${idx+15})`);
      params.push(
        item.tier, item.exam, "multiple_choice", "published",
        item.stem, JSON.stringify(item.options), JSON.stringify([item.correct]),
        item.rationale, item.diff, item.bs, "BOTH", hash(item.stem),
        item.topic, item.subtopic, "{" + item.tags.join(",") + "}", item.clinicalPearl
      );
      idx += 16;
    }
    const sql = `INSERT INTO exam_questions (tier, exam, question_type, status, stem, options, correct_answer, rationale, difficulty, body_system, region_scope, stem_hash, topic, subtopic, tags, clinical_pearl)
                 SELECT v.* FROM (VALUES ${values.join(",")}) AS v(tier,exam,question_type,status,stem,options,correct_answer,rationale,difficulty,body_system,region_scope,stem_hash,topic,subtopic,tags,clinical_pearl)
                 WHERE NOT EXISTS (SELECT 1 FROM exam_questions e WHERE e.stem_hash = v.stem_hash)`;
    const result = await pool.query(sql, params);
    inserted += result.rowCount || 0;
    console.log(`[RN-MedSurg-Pharm-B2] Batch ${Math.floor(i/batchSize)+1}: inserted ${result.rowCount || 0} questions`);
  }
  console.log(`\n[RN-MedSurg-Pharm-B2] Total inserted: ${inserted}/${QS.length}`);
  const counts = await pool.query(`SELECT tier, count(*) as cnt FROM exam_questions WHERE status='published' GROUP BY tier ORDER BY tier`);
  counts.rows.forEach((r: any) => console.log(`  ${r.tier}: ${r.cnt}`));
  await pool.end();
}

main().catch(e => { console.error(e); process.exit(1); });
